    // Optimize ptrtoint(gep(ptrtoint(x), size)) -> ptrtoint(x) + size
    // Specifically, for the pattern:
    //   %ptr.addr = ptrtoint ptr %ptr to i64
    //   %size = sub i64 %end.addr, %ptr.addr
    //   %end = getelementptr i8, ptr %ptr, i64 %size
    //   %end.addr2 = ptrtoint ptr %end to i64
    // We can simplify %end.addr2 to %end.addr.
    if (CastOpc == Instruction::PtrToInt && isa<GetElementPtrInst>(Op)) {
      auto *GEP = cast<GetElementPtrInst>(Op);
      Value *Ptr = GEP->getPointerOperand();
      if (Ptr->getType()->isPointerTy() && Ty->isIntegerTy()) {
        // Look for: ptrtoint(gep(p, offset)) where p came from a ptrtoint
        if (auto *Offset = GEP->getOperand(1)) {
          // We now want to see if this fits the pattern:
          //   gep(p, sub(end_addr, ptrtoint(p)))
          if (match(Offset, m_Sub(m_Value(), m_PtrToInt(m_Specific(Ptr)))))
            return Offset; // This is: sub(end_addr, ptrtoint(p)) -> end_addr is our result
        }
      }
    }

    // bitcast x -> x
    if (CastOpc == Instruction::BitCast)
      if (Op->getType() == Ty)
        return Op;

    return nullptr;
}

